def range_summary(nums):
    if not nums:
        return ''

    # remove duplicates and sort numbers
    distinct_nums = sorted(set(nums))

    ranges = []
    start = distinct_nums[0]
    end = distinct_nums[0]

    for num in distinct_nums[1:]:
        if num == end + 1:
            end = num
        else:
            if start == end:
                ranges.append(str(start))
            else:
                ranges.append(f'{start}-{end}')
            start = num
            end = num

    # handle last range or single number
    if start == end:
        ranges.append(str(start))
    else:
        ranges.append(f'{start}-{end}')

    return ','.join(ranges)
